// Handle workflow errors and prepare error report
const errorItems = $input.all();

if (errorItems.length === 0) {
  return [];
}

const errors = errorItems.map(item => {
  const error = item.json.error || {};
  return {
    error_type: error.name || "Unknown Error",
    error_message: error.message || "No error message available",
    failed_node: item.json.node || "Unknown Node",
    timestamp: new Date().toISOString(),
    stack_trace: error.stack || ""
  };
});

return [{ json: errors[0] }];

// Normalize & merge Hunter.io response with original scraped data
const originalItems = $items("Format & Validate Data");
const hunterItems = $input.all();
const errors = [];

const merged = hunterItems.map((hunterItem, index) => {
  const original = originalItems[index]?.json || {};

  // Default email data
  let emailData = {
    email: null,
    email_confidence: "Low",
    email_source: "hunter_not_found",
    email_reasoning: "Hunter did not return a valid email",
    alternative_emails: ""
  };

  try {
    // Handle Hunter API error
    if (hunterItem.json?.errors || hunterItem.json?.error) {
      errors.push({
        business: original.business_name,
        error: hunterItem.json.errors || hunterItem.json.error
      });
    } else {
      const emails = hunterItem.json?.data?.emails || [];

      if (Array.isArray(emails) && emails.length > 0) {
        // Sort by confidence (highest first)
        emails.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
        const best = emails[0];

        // Confidence mapping
        const confidence =
          best.confidence >= 85 ? "High" :
          best.confidence >= 65 ? "Medium" : "Low";

        emailData.email = best.value || null;
        emailData.email_confidence = confidence;
        emailData.email_source = "hunter.io";
        emailData.email_reasoning = `Found via Hunter domain search (${best.confidence || 0}% confidence)`;
        emailData.alternative_emails = emails
          .slice(1)
          .map(e => e.value)
          .filter(Boolean)
          .join(", ");

        // Email format validation
        if (emailData.email) {
          const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
          if (!emailRegex.test(emailData.email)) {
            emailData.email = null;
            emailData.email_confidence = "Low";
            emailData.email_source = "invalid_format";
            emailData.email_reasoning = "Invalid email format returned by Hunter";
          }
        }
      }
    }
  } catch (e) {
    errors.push({
      business: original.business_name,
      error: `Hunter parse error: ${e.message}`
    });
  }

  // ✅ FINAL OUTPUT — MATCHES YOUR REQUIRED FIELDS EXACTLY
  return {
    json: {
      business_name: original.business_name || "",
      address: original.address || "",
      phone: original.phone || "",
      website: original.website || "",
      google_maps_url: original.google_maps_url || "",
      category: original.category || "",
      rating: original.rating ?? null,
      reviews_count: original.reviews_count ?? 0,
      latitude: original.latitude ?? null,
      longitude: original.longitude ?? null,
      data_quality_score: original.data_quality_score ?? 0,

      email: emailData.email,
      email_confidence: emailData.email_confidence,
      email_source: emailData.email_source,
      email_reasoning: emailData.email_reasoning,
      alternative_emails: emailData.alternative_emails,

      processed_date: new Date().toISOString(),
      workflow_version: "2.0"
    }
  };
});

// Attach errors (if any) to first item
if (errors.length > 0 && merged.length > 0) {
  merged[0].json._errors = errors;
}

return merged;

// ===============================
// STEP 1: Validate Scraper Response
// ===============================
const inputItems = $input.all();

if (!inputItems || inputItems.length === 0) {
  throw new Error('No data received from Google Maps Scraper');
}

// Normalize raw input
const rawJson = inputItems.map(i => i.json).flat();

// Detect businesses array
let businesses = [];

if (rawJson[0]?.items && Array.isArray(rawJson[0].items)) {
  businesses = rawJson[0].items;
} else if (Array.isArray(rawJson)) {
  businesses = rawJson;
} else {
  throw new Error('Invalid response format from scraper');
}

if (!businesses || businesses.length === 0) {
  throw new Error('No businesses found in scraper results');
}

// ===============================
// STEP 2: Clean, Format & Score Data
// ===============================
const cleanedBusinesses = businesses.map(b => {
  const business = {
    business_name: (b.title || b.name || "").trim(),
    address: (b.address || b.formattedAddress || "").trim(),
    phone: (b.phone || b.phoneNumber || "").trim(),
    website: (b.website || b.websiteUrl || "").trim(),
    google_maps_url: (b.url || b.placeUrl || "").trim(),
    category: Array.isArray(b.categories)
      ? b.categories.join(", ")
      : (b.category || ""),
    rating: b.rating || b.totalScore || null,
    reviews_count: b.reviewsCount || b.reviews || 0,
    latitude: b.latitude || b.lat || null,
    longitude: b.longitude || b.lng || null,
    raw_data: JSON.stringify(b)
  };

  // ===============================
  // STEP 3: Data Quality Scoring (0–100)
  // ===============================
  let qualityScore = 0;
  if (business.business_name) qualityScore += 25;
  if (business.phone) qualityScore += 20;
  if (business.website) qualityScore += 30;
  if (business.address) qualityScore += 15;
  if (business.rating && business.rating >= 3.5) qualityScore += 10;

  business.data_quality_score = qualityScore;

  return business;
});

// ===============================
// STEP 4: Filter Low-Quality Leads
// ===============================
const finalLeads = cleanedBusinesses.filter(b =>
  b.business_name &&
  b.google_maps_url &&
  b.data_quality_score >= 40
);

if (finalLeads.length === 0) {
  throw new Error('No valid businesses after quality filtering');
}

// ===============================
// STEP 5: Return Final Output
// ===============================
return finalLeads.map(b => ({
  json: b
}));
